package com.programovil.aura.regionsync.presentation\n\nimport androidx.lifecycle.ViewModel\nimport androidx.lifecycle.viewModelScope\nimport com.programovil.aura.regionsync.domain.model.Region\nimport com.programovil.aura.regionsync.domain.model.RegionalDataItem\nimport com.programovil.aura.regionsync.domain.usecase.GetActiveRegionsUseCase\nimport com.programovil.aura.regionsync.domain.usecase.SyncRegionalDataUseCase\nimport com.programovil.aura.regionsync.domain.repository.RegionSyncRepository\nimport kotlinx.coroutines.flow.MutableStateFlow\nimport kotlinx.coroutines.flow.StateFlow\nimport kotlinx.coroutines.flow.asStateFlow\nimport kotlinx.coroutines.flow.flatMapLatest\nimport kotlinx.coroutines.launch\n\nclass RegionalSyncViewModel(\n    private val getActiveRegionsUseCase: GetActiveRegionsUseCase,\n    private val syncRegionalDataUseCase: SyncRegionalDataUseCase,\n    private val regionSyncRepository: RegionSyncRepository // Used for direct flow access\n) : ViewModel() {\n\n    private val _activeRegions = MutableStateFlow<List<Region>>(emptyList())\n    val activeRegions: StateFlow<List<Region>> = _activeRegions.asStateFlow()\n\n    private val _selectedRegion = MutableStateFlow<Region?>(null)\n    val selectedRegion: StateFlow<Region?> = _selectedRegion.asStateFlow()\n\n    val regionalData: StateFlow<List<RegionalDataItem>> = _selectedRegion.flatMapLatest {\ region ->\n        region?.let { regionSyncRepository.getRegionalDataFlow(it.id) } ?: MutableStateFlow(emptyList())\n    }.asStateFlow()\n\n    private val _syncing = MutableStateFlow(false)\n    val syncing: StateFlow<Boolean> = _syncing.asStateFlow()\n\n    private val _message = MutableStateFlow<String?>(null)\n    val message: StateFlow<String?> = _message.asStateFlow()\n\n    init {\n        viewModelScope.launch {\n            loadActiveRegions()\n        }\n    }\n\n    fun selectRegion(region: Region) {\n        _selectedRegion.value = region\n    }\n\n    fun performSync() {\n        viewModelScope.launch {\n            _syncing.value = true\n            _message.value = \"Synchronizing...\"\n            try {\n                syncRegionalDataUseCase()\n                _message.value = \"Synchronization complete!\"\n            } catch (e: Exception) {\n                _message.value = \"Synchronization failed: ${e.localizedMessage}\"\n            } finally {\n                _syncing.value = false\n            }\n        }\n    }\n\n    private suspend fun loadActiveRegions() {\n        try {\n            val regions = getActiveRegionsUseCase()\n            _activeRegions.value = regions\n            if (regions.isNotEmpty() && _selectedRegion.value == null) {\n                _selectedRegion.value = regions.first()\n            }\n        } catch (e: Exception) {\n            _message.value = \"Failed to load active regions: ${e.localizedMessage}\"\n        }\n    }\n}\n